const body = $input.first().json.body || $input.first().json;

const sessionId = body.session_id;
const pregunta = body.pregunta || body.question;
const requestId = body.request_id;
const includeHistory = body.include_history !== false;

if (!sessionId) throw new Error('session_id es requerido');
if (!pregunta) throw new Error('pregunta es requerida');
if (!requestId) throw new Error('request_id es requerido');

return [{
  json: {
    session_id: sessionId,
    pregunta: pregunta,
    request_id: requestId,
    include_history: includeHistory
  }
}];

const inputData = $('Extraer y validar datos').first().json;
const dbData = $input.first().json;

const storeNames = [];
if (dbData.base_store) storeNames.push(dbData.base_store);
if (dbData.session_store) storeNames.push(dbData.session_store);

if (storeNames.length === 0) {
  throw new Error('No hay stores RAG disponibles para esta sesión.');
}

const historialRows = dbData.historial || [];
const historial = historialRows
  .reverse()
  .flatMap(row => ([
    { role: 'user', parts: [{ text: row.question }] },
    { role: 'model', parts: [{ text: row.answer }] }
  ]));

const systemPrompt = `Eres ASAI, un auditor interno experto certificado por el IIA (Institute of Internal Auditors) con más de 20 años de experiencia.

CONTEXTO DE ESTA AUDITORÍA:
- Tenés acceso a dos repositorios de documentos:
  1. Repositorio base: normas IIA, marcos de referencia y documentación técnica
  2. Repositorio de evidencias: documentos específicos subidos por el equipo auditor para esta auditoría

CÓMO DEBES RESPONDER:
- SIEMPRE buscá primero en los documentos disponibles antes de usar tu conocimiento general
- Si encontrás información en los documentos, citá la fuente específica (nombre del documento, página si está disponible)
- Si la pregunta involucra datos numéricos o transacciones, hacé los cálculos y presentá los resultados en tablas cuando sea útil
- Si detectás anomalías o riesgos en los datos, destacalos proactivamente aunque no te los hayan pedido explícitamente
- Cuando cites normas IIA, indicá el número y nombre exacto de la norma
- Si no encontrás suficiente información en los documentos, indicalo claramente y separalo de lo que sí encontraste

FORMATO DE RESPUESTA:
- Usá markdown para estructurar la respuesta (títulos, listas, tablas)
- Primero respondé la pregunta directamente
- Luego agregá el fundamento normativo si aplica
- Si hay hallazgos adicionales relevantes, mencionálos al final como "Hallazgos adicionales"

TONO: Profesional, preciso y orientado a acción. El auditor necesita información útil para tomar decisiones.`;

return [{
  json: {
    session_id: inputData.session_id,
    pregunta: inputData.pregunta,
    request_id: inputData.request_id,
    store_names: storeNames,
    historial: historial,
    system_prompt: systemPrompt,
    historial_count: historial.length
  }
}];

const geminiResponse = $input.first().json;
const contextData = $('Construir contexto RAG').first().json;

let respuesta = '';
try {
  if (geminiResponse.content?.parts?.[0]?.text) {
    respuesta = geminiResponse.content.parts[0].text;
  } else if (geminiResponse.text) {
    respuesta = geminiResponse.text;
  } else if (geminiResponse.candidates?.[0]?.content?.parts?.[0]?.text) {
    respuesta = geminiResponse.candidates[0].content.parts[0].text;
  } else {
    respuesta = 'Sin respuesta';
  }
} catch(e) {
  respuesta = 'Error: ' + e.message;
}

function detectarFuente(texto, tituloGemini) {
  if (tituloGemini) return tituloGemini;
  if (!texto) return 'Documento de evidencia';
  if (texto.includes('ID_Factura') || texto.includes('ID_Pago')) return 'DB Facturas y Pagos';
  if (texto.includes('ID_Proveedor') || texto.includes('ID_Empleado')) return 'DB Maestro Proveedores y Empleados';
  if (texto.includes('Plan de Auditoría') || texto.includes('pruebas de control')) return 'Plan de Auditoría';
  if (texto.includes('Norma') || texto.includes('IIA') || texto.includes('MIPP')) return 'Normas IIA';
  return 'Documento de evidencia';
}

const fuentes = [];
try {
  const chunks = geminiResponse.groundingMetadata?.groundingChunks || [];
  for (const chunk of chunks) {
    const ctx = chunk.retrievedContext;
    if (ctx) {
      const nombre = detectarFuente(ctx.text, ctx.title);
      fuentes.push({
        nombre: nombre,
        extracto: ctx.text?.substring(0, 150),
        pagina: ctx.pageNumber || null,
        store: ctx.fileSearchStore
      });
    }
  }
} catch(e) {}

const fuentesUnicas = fuentes.filter((f, index, self) =>
  index === self.findIndex(t => t.nombre === f.nombre)
);

const tokensEntrada = geminiResponse.usageMetadata?.promptTokenCount || 0;
const tokensSalida = geminiResponse.usageMetadata?.candidatesTokenCount || 0;

return [{
  json: {
    session_id: contextData.session_id,
    pregunta: contextData.pregunta,
    request_id: contextData.request_id,
    respuesta: respuesta,
    fuentes: fuentesUnicas,
    tokens_entrada: tokensEntrada,
    tokens_salida: tokensSalida,
    historial_mensajes_usados: contextData.historial_count
  }
}];
